+        let row = conn.query_row("SELECT 2 IN (1, NULL, 3);").unwrap();
+        assert_eq!(row_values(&row), vec![SqliteValue::Null]);
+    }
+
+    #[test]
+    fn in_list_with_null_match_returns_true() {
+        let conn = Connection::open(":memory:").unwrap();
